static int handle_upload_notes_to_ftp(const rpc_request_t* request, rpc_response_t* response) {
    FtpConfig config;
    int rc = db_ftp_config_get_by_user(request->user_id, &config);
    if (rc != 0) {
        response->status = RPC_ERROR_NOT_FOUND;
        snprintf(response->message, sizeof(response->message), "FTP config not found");
        return -1;
    }

    // 漏洞点1：先保存配置
    rc = db_ftp_config_update(request->user_id, request->ftp_host,
                               request->ftp_port, request->ftp_user,
                               request->ftp_pass, request->ftp_path);
    if (rc != 0) {
        response->status = RPC_ERROR_INTERNAL;
        snprintf(response->message, sizeof(response->message), "Failed to save FTP config");
        return -1;
    }

    // 漏洞点2：上传前用system拼接IP做ping测试
    char cmd[512];

    // 漏洞：这里直接拼接用户输入的FTP主机名
    // 攻击者可以注入: 192.168.1.1; cat /etc/passwd
    snprintf(cmd, sizeof(cmd), "ping -c 1 %s > /dev/null 2>&1 && echo OK", config.ftp_host);

    // 命令注入漏洞点
    int ping_result = system(cmd);

    if (ping_result != 0) {
        response->status = RPC_ERROR_FAILED;
        snprintf(response->message, sizeof(response->message), "Cannot connect to FTP server");
        return -1;
    }

    // 模拟上传成功
    response->status = RPC_SUCCESS;
    snprintf(response->message, sizeof(response->message), "Notes uploaded to FTP");
    return 0;
}

int note_upload_notes_to_ftp(int user_id, const char* host, const char* path) {
    FtpConfig config;
    int rc = db_ftp_config_get_by_user(user_id, &config);
    if (rc != 0) {
        return -1;
    }

    // 漏洞点：这里用system拼接IP做ping测试
    // 攻击者可以注入命令
    char cmd[512];
    snprintf(cmd, sizeof(cmd), "ping -c 1 %s > /dev/null 2>&1 && echo OK", host);

    // 命令注入漏洞点
    int ping_result = system(cmd);

    if (ping_result != 0) {
        return -2;
    }

    return 0;
}

static int handle_upload_notes(struct mg_connection* conn, void* cbdata) {
    char user_id_str[32], host[256];
    if (!get_param(conn, "user_id", user_id_str, sizeof(user_id_str)) ||
        !get_param(conn, "host", host, sizeof(host))) {
        send_json(conn, 400, "Missing parameters", NULL);
        return 200;
    }

    int user_id = atoi(user_id_str);
    int rc = note_upload_notes_to_ftp(user_id, host, "/");

    send_json(conn, rc == 0 ? 200 : 500, rc == 0 ? "Notes uploaded to FTP" : "Failed to upload notes", NULL);
    return 200;
}

static const char* get_param(struct mg_connection* conn, const char* name, char* buf, size_t buf_size) {
    const struct mg_request_info* ri = mg_get_request_info(conn);

    // 先尝试从 query_string 获取 (GET 请求)
    if (ri->query_string) {
        int len = mg_get_var(ri->query_string, strlen(ri->query_string), name, buf, buf_size);
        if (len > 0) return buf;
    }

    // 尝试从 POST 数据获取
    // 读取 POST 数据
    char post_data[MAX_POST_DATA];
    int post_len = mg_read(conn, post_data, sizeof(post_data) - 1);
    if (post_len > 0) {
        post_data[post_len] = '\0';
        int len = mg_get_var(post_data, post_len, name, buf, buf_size);
        if (len > 0) return buf;
    }

    return NULL;
}
